package com.enterprise.auth.service;

import com.enterprise.auth.entity.AuditEventType;
import com.enterprise.auth.entity.AuditLog;
import com.enterprise.auth.entity.User;
import com.enterprise.auth.repository.AuditLogRepository;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Propagation;
import org.springframework.transaction.annotation.Transactional;

@Service
public class AuditService {

    private static final Logger logger = LoggerFactory.getLogger(AuditService.class);

    private final AuditLogRepository auditLogRepository;

    public AuditService(AuditLogRepository auditLogRepository) {
        this.auditLogRepository = auditLogRepository;
    }

    @Transactional(propagation = Propagation.REQUIRES_NEW)
    public void logEvent(User user, AuditEventType eventType, String description,
                         String ipAddress, String userAgent, boolean success) {
        try {
            AuditLog auditLog = new AuditLog();
            auditLog.setUser(user);
            auditLog.setEventType(eventType);
            auditLog.setDescription(sanitizeForLog(description));
            auditLog.setIpAddress(sanitizeIpAddress(ipAddress));
            auditLog.setUserAgent(sanitizeUserAgent(userAgent));
            auditLog.setSuccess(success);
            auditLogRepository.save(auditLog);

            logger.info("Audit event: type={}, user={}, success={}, ip={}",
                    eventType, user.getUsername(), success, sanitizeIpAddress(ipAddress));
        } catch (Exception e) {
            logger.error("Failed to write audit log for user={}, event={}",
                    user.getUsername(), eventType, e);
        }
    }

    private String sanitizeForLog(String input) {
        if (input == null) return null;
        return input.replaceAll("[\\r\\n]", "").substring(0, Math.min(input.length(), 500));
    }

    private String sanitizeIpAddress(String ip) {
        if (ip == null) return null;
        return ip.replaceAll("[^0-9a-fA-F.:]", "").substring(0, Math.min(ip.length(), 45));
    }

    private String sanitizeUserAgent(String ua) {
        if (ua == null) return null;
        return ua.substring(0, Math.min(ua.length(), 500));
    }
}

