@Service
public class BackupCodeService {

    private static final Logger logger = LoggerFactory.getLogger(BackupCodeService.class);

    private final BackupCodeRepository backupCodeRepository;
    private final UserRepository userRepository;
    private final BackupCodeGenerator backupCodeGenerator;
    private final PasswordEncoder passwordEncoder;
    private final AuditService auditService;

    @Value("${app.backup-codes.count:10}")
    private int backupCodeCount;

    @Value("${app.backup-codes.expiry-days:365}")
    private int backupCodeExpiryDays;

    @Value("${app.backup-codes.max-failed-attempts:5}")
    private int maxFailedAttempts;

    @Value("${app.backup-codes.lockout-duration-minutes:30}")
    private int lockoutDurationMinutes;

    @Value("${app.backup-codes.rate-limit-window-minutes:5}")
    private int rateLimitWindowMinutes;

    @Value("${app.backup-codes.rate-limit-max-attempts:3}")
    private int rateLimitMaxAttempts;

    public BackupCodeService(BackupCodeRepository backupCodeRepository,
                             UserRepository userRepository,
                             BackupCodeGenerator backupCodeGenerator,
                             PasswordEncoder passwordEncoder,
                             AuditService auditService) {
        this.backupCodeRepository = backupCodeRepository;
        this.userRepository = userRepository;
        this.backupCodeGenerator = backupCodeGenerator;
        this.passwordEncoder = passwordEncoder;
        this.auditService = auditService;
    }

    @Transactional
    public List<String> generateBackupCodes(User user, String ipAddress, String userAgent) {
        // Invalidate all existing backup codes
        backupCodeRepository.deleteAllByUser(user);

        List<String> plainCodes = backupCodeGenerator.generateBackupCodes(backupCodeCount);
        Instant expiresAt = Instant.now().plus(Duration.ofDays(backupCodeExpiryDays));

        for (String plainCode : plainCodes) {
            String hashedCode = passwordEncoder.encode(normalizeCode(plainCode));
            BackupCode backupCode = new BackupCode(user, hashedCode, expiresAt);
            backupCodeRepository.save(backupCode);
        }

        auditService.logEvent(user, AuditEventType.BACKUP_CODES_GENERATED,
                "Generated " + backupCodeCount + " backup codes", ipAddress, userAgent, true);

        logger.info("Generated {} backup codes for user: {}", backupCodeCount, user.getUsername());

        return plainCodes;
    }

    @Transactional
    public boolean validateBackupCode(User user, String providedCode, String ipAddress, String userAgent) {
        // Check account lock
        if (user.isAccountLocked()) {
            if (isLockoutExpired(user)) {
                unlockAccount(user, ipAddress, userAgent);
            } else {
                auditService.logEvent(user, AuditEventType.BACKUP_CODE_FAILED,
                        "Attempt on locked account", ipAddress, userAgent, false);
                throw new AccountLockedException(
                        "Account is locked due to too many failed attempts. Please try again later.");
            }
        }

        // Rate limiting check
        checkRateLimit(user, ipAddress, userAgent);

        String normalizedCode = normalizeCode(providedCode);
        List<BackupCode> validCodes = backupCodeRepository.findValidBackupCodes(user);

        if (validCodes.isEmpty()) {
            recordFailedAttempt(user, ipAddress, userAgent);
            return false;
        }

        for (BackupCode backupCode : validCodes) {
            // Use constant-time comparison via BCrypt's built-in check
            if (passwordEncoder.matches(normalizedCode, backupCode.getCodeHash())) {
                // Mark code as used
                backupCode.setUsed(true);
                backupCode.setUsedAt(Instant.now());
                backupCode.setUsedIpAddress(ipAddress);
                backupCodeRepository.save(backupCode);

                // Reset failed attempts on success
                user.setFailedBackupCodeAttempts(0);
                user.setLastFailedBackupAttempt(null);
                userRepository.save(user);

                auditService.logEvent(user, AuditEventType.BACKUP_CODE_USED,
                        "Backup code used successfully", ipAddress, userAgent, true);

                long remaining = backupCodeRepository.countValidBackupCodes(user);
                if (remaining <= 2) {
                    logger.warn("User {} has only {} backup codes remaining", user.getUsername(), remaining);
                }

                logger.info("Backup code validated successfully for user: {}", user.getUsername());
                return true;
            }
        }

        recordFailedAttempt(user, ipAddress, userAgent);
        return false;
    }

    @Transactional
    public List<String> regenerateBackupCodes(User user, String ipAddress, String userAgent) {
        if (!user.isMfaEnabled()) {
            throw new MfaException("MFA must be enabled to regenerate backup codes");
        }

        auditService.logEvent(user, AuditEventType.BACKUP_CODES_REGENERATED,
                "Backup codes regenerated", ipAddress, userAgent, true);

        return generateBackupCodes(user, ipAddress, userAgent);
    }

    public long getRemainingBackupCodeCount(User user) {
        return backupCodeRepository.countValidBackupCodes(user);
    }

    private String normalizeCode(String code) {
        if (code == null) return "";
        return code.trim().toUpperCase().replace("-", "").replace(" ", "");
    }

    private void checkRateLimit(User user, String ipAddress, String userAgent) {
        Instant windowStart = Instant.now().minus(Duration.ofMinutes(rateLimitWindowMinutes));
        if (user.getLastFailedBackupAttempt() != null
                && user.getLastFailedBackupAttempt().isAfter(windowStart)
                && user.getFailedBackupCodeAttempts() >= rateLimitMaxAttempts) {
            auditService.logEvent(user, AuditEventType.BACKUP_CODE_RATE_LIMITED,
                    "Rate limit exceeded for backup code attempts", ipAddress, userAgent, false);
            throw new RateLimitExceededException(
                    "Too many backup code attempts. Please wait before trying again.");
        }
    }

    private void recordFailedAttempt(User user, String ipAddress, String userAgent) {
        user.setFailedBackupCodeAttempts(user.getFailedBackupCodeAttempts() + 1);
        user.setLastFailedBackupAttempt(Instant.now());

        if (user.getFailedBackupCodeAttempts() >= maxFailedAttempts) {
            user.setAccountLocked(true);
            auditService.logEvent(user, AuditEventType.ACCOUNT_LOCKED,
                    "Account locked after " + maxFailedAttempts + " failed backup code attempts",
                    ipAddress, userAgent, false);
            logger.warn("Account locked for user: {} after {} failed backup code attempts",
                    user.getUsername(), maxFailedAttempts);
        }

        userRepository.save(user);

        auditService.logEvent(user, AuditEventType.BACKUP_CODE_FAILED,
                "Failed backup code attempt #" + user.getFailedBackupCodeAttempts(),
                ipAddress, userAgent, false);
    }

    private boolean isLockoutExpired(User user) {
        if (user.getLastFailedBackupAttempt() == null) return true;
        Instant lockoutEnd = user.getLastFailedBackupAttempt()
                .plus(Duration.ofMinutes(lockoutDurationMinutes));
        return Instant.now().isAfter(lockoutEnd);
    }

    private void unlockAccount(User user, String ipAddress, String userAgent) {
        user.setAccountLocked(false);
        user.setFailedBackupCodeAttempts(0);
        user.setLastFailedBackupAttempt(null);
        userRepository.save(user);
        auditService.logEvent(user, AuditEventType.ACCOUNT_UNLOCKED,
                "Account unlocked after lockout period expired", ipAddress, userAgent, true);
    }
}

// src/main/java/com/enterprise/auth/service/MfaService.java
package com.enterprise.auth.service;

import com.enterprise.auth.dto.MfaSetupResponse;
import com.enterprise.auth.entity.AuditEventType;
import com.enterprise.auth.entity.User;
import com.enterprise.auth.exception.MfaException;
import com.enterprise.auth.repository.UserRepository;
import dev.samstevens.totp.code.CodeGenerator;
import dev.samstevens.totp.code.CodeVerifier;
import dev.samstevens.totp.code.DefaultCodeGenerator;
import dev.samstevens.totp.code.DefaultCodeVerifier;
import dev.samstevens.totp.code.HashingAlgorithm;
import dev.samstevens.totp.secret.DefaultSecretGenerator;
import dev.samstevens.totp.secret.SecretGenerator;
import dev.samstevens.totp.time.SystemTimeProvider;
import dev.samstevens.totp.time.TimeProvider;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;

@Service
public class MfaService {

    private static final Logger logger = LoggerFactory.getLogger(MfaService.class);

    private final UserRepository userRepository;
    private final BackupCodeService backupCodeService;
    private final AuditService auditService;
    private final SecretGenerator secretGenerator;
    private final CodeVerifier codeVerifier;

    @Value("${app.mfa.issuer:EnterpriseAuth}")
    private String issuer;

    public MfaService(UserRepository userRepository,
                      BackupCodeService backupCodeService,
                      AuditService auditService) {
        this.userRepository = userRepository;
        this.backupCodeService = backupCodeService;
        this.auditService = auditService;
        this.secretGenerator = new DefaultSecretGenerator(32);

        TimeProvider timeProvider = new SystemTimeProvider();
        CodeGenerator codeGenerator = new DefaultCodeGenerator(HashingAlgorithm.SHA256);
        this.codeVerifier = new DefaultCodeVerifier(codeGenerator, timeProvider);
    }

    @Transactional
    public MfaSetupResponse setupMfa(User user, String ipAddress, String userAgent) {
        if (user.isMfaEnabled()) {
            throw new MfaException("MFA is already enabled for this account");
        }

        String secret = secretGenerator.generate();
        user.setMfaSecret(secret);
        userRepository.save(user);

        String qrCodeUri = String.format("otpauth://totp/%s:%s?secret=%s&issuer=%s&algorithm=SHA256&digits=6&period=30",
                issuer, user.getEmail(), secret, issuer);

        logger.info("MFA setup initiated for user: {}", user.getUsername());

        return new MfaSetupResponse(secret, qrCodeUri, null,
                "Scan the QR code with your authenticator app, then verify with a TOTP code to complete setup.");
    }

    @Transactional
    public MfaSetupResponse confirmMfaSetup(User user, String totpCode, String ipAddress, String userAgent) {
        if (user.isMfaEnabled()) {
            throw new MfaException("MFA is already enabled");
        }

        if (user.getMfaSecret() == null) {
            throw new MfaException("MFA setup has not been initiated. Please start setup first.");
        }

        if (!codeVerifier.isValidCode(user.getMfaSecret(), totpCode)) {
            auditService.logEvent(user, AuditEventType.MFA_FAILED,
                    "Invalid TOTP code during MFA setup confirmation", ipAddress, userAgent, false);
            throw new MfaException("Invalid TOTP code. Please try again.");
        }

        user.setMfaEnabled(true);
        userRepository.save(user);

        List<String> backupCodes = backupCodeService.generateBackupCodes(user, ipAddress, userAgent);

        auditService.logEvent(user, AuditEventType.MFA_ENABLED,
                "MFA enabled successfully", ipAddress, userAgent, true);

        logger.info("MFA enabled for user: {}", user.getUsername());

        return new MfaSetupResponse(null, null, backupCodes,
                "MFA has been enabled. Save these backup codes in a secure location. They will not be shown again.");
    }

    @Transactional
    public void disableMfa(User user, String totpCode, String ipAddress, String userAgent) {
        if (!user.isMfaEnabled()) {
            throw new MfaException("MFA is not enabled");
        }

        if (!codeVerifier.isValidCode(user.getMfaSecret(), totpCode)) {
            auditService.logEvent(user, AuditEventType.MFA_FAILED,
                    "Invalid TOTP code during MFA disable", ipAddress, userAgent, false);
            throw new MfaException("Invalid TOTP code");
        }

        user.setMfaEnabled(false);
        user.setMfaSecret(null);
        userRepository.save(user);

        auditService.logEvent(user, AuditEventType.MFA_DISABLED,
                "MFA disabled", ipAddress, userAgent, true);

        logger.info("MFA disabled for user: {}", user.getUsername());
    }

    public boolean verifyTotpCode(User user, String totpCode) {
        if (!user.isMfaEnabled() || user.getMfaSecret() == null) {
            return false;
        }
        return codeVerifier.isValidCode(user.getMfaSecret(), totpCode);
    }
}

// src/main/java/com/enterprise/auth/service/AuthenticationService.java
package com.enterprise.auth.service;

import com.enterprise.auth.entity.AuditEventType;
import com.enterprise.auth.entity.User;
import com.enterprise.auth.exception.AccountLockedException;
import com.enterprise.auth.exception.MfaException;
import com.enterprise.auth.repository.UserRepository;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
public class AuthenticationService {

    private static final Logger logger = LoggerFactory.getLogger(AuthenticationService.class);

    private final UserRepository userRepository;
    private final PasswordEncoder passwordEncoder;
    private final BackupCodeService backupCodeService;
    private final MfaService mfaService;
    private final AuditService auditService;

    // Generic error message to prevent user enumeration
    private static final String INVALID_CREDENTIALS_MSG = "Invalid credentials or backup code";

    public AuthenticationService(UserRepository userRepository,
                                 PasswordEncoder passwordEncoder,
                                 BackupCodeService backupCodeService,
                                 MfaService mfaService,
                                 AuditService auditService) {
        this.userRepository = userRepository;
        this.passwordEncoder = passwordEncoder;
        this.backupCodeService = backupCodeService;
        this.mfaService = mfaService;
        this.auditService = auditService;
    }

    @Transactional
    public User authenticateWithBackupCode(String username, String password, String backupCode,
                                           String ipAddress, String userAgent) {
        // Use constant-time-safe approach: always perform password check even if user not found
        User user = userRepository.findByUsername(username).orElse(null);

        if (user == null) {
            // Perform a dummy password encode to prevent timing attacks
            passwordEncoder.encode("dummy-password-for-timing");
            logger.warn("Authentication attempt for non-existent user from IP: {}", ipAddress);
            throw new MfaException(INVALID_CREDENTIALS_MSG);
        }

        if (user.isAccountLocked()) {
            auditService.logEvent(user, AuditEventType.LOGIN_FAILED,
                    "Login attempt on locked account", ipAddress, userAgent, false);
            throw new AccountLockedException("Account is locked. Please contact support.");
        }

        // Verify password first
        if (!passwordEncoder.matches(password, user.getPassword())) {
            auditService.logEvent(user, AuditEventType.LOGIN_FAILED,
                    "Invalid password during backup code authentication", ipAddress, userAgent, false);
            throw new MfaException(INVALID_CREDENTIALS_MSG);
        }

        // Verify MFA is enabled
        if (!user.isMfaEnabled()) {
            throw new MfaException("MFA is not enabled for this account. Use standard login.");
        }

        // Validate backup code
        boolean isValid = backupCodeService.validateBackupCode(user, backupCode, ipAddress, userAgent);

        if (!isValid) {
            throw new MfaException(INVALID_CREDENTIALS_MSG);
        }

        auditService.logEvent(user, AuditEventType.LOGIN_SUCCESS,
                "Authenticated using backup code", ipAddress, userAgent, true);

        logger.info("User {} authenticated using backup code from IP: {}", username, ipAddress);

        return user;
    }
}

