package com.enterprise.auth.controller;

import com.enterprise.auth.dto.ApiResponse;
import com.enterprise.auth.dto.BackupCodeAuthRequest;
import com.enterprise.auth.entity.User;
import com.enterprise.auth.service.AuthenticationService;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.validation.Valid;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/auth")
public class AuthController {

    private final AuthenticationService authenticationService;

    public AuthController(AuthenticationService authenticationService) {
        this.authenticationService = authenticationService;
    }

    @PostMapping("/backup-code-login")
    public ResponseEntity<ApiResponse<String>> loginWithBackupCode(
            @Valid @RequestBody BackupCodeAuthRequest request,
            HttpServletRequest httpRequest) {

        String ipAddress = getClientIpAddress(httpRequest);
        String userAgent = httpRequest.getHeader("User-Agent");

        User user = authenticationService.authenticateWithBackupCode(
                request.getUsername(),
                request.getPassword(),
                request.getBackupCode(),
                ipAddress,
                userAgent
        );

        return ResponseEntity.ok(ApiResponse.success(
                "Authentication successful. Please note: your backup code has been consumed.",
                "authenticated"
        ));
    }

    private String getClientIpAddress(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            // Take the first IP in the chain (original client)
            return xForwardedFor.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }
}

// src/main/java/com/enterprise/auth/controller/MfaController.java
package com.enterprise.auth.controller;

import com.enterprise.auth.dto.ApiResponse;
import com.enterprise.auth.dto.EnableMfaRequest;
import com.enterprise.auth.dto.MfaSetupResponse;
import com.enterprise.auth.entity.User;
import com.enterprise.auth.repository.UserRepository;
import com.enterprise.auth.service.MfaService;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.validation.Valid;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.Authentication;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/mfa")
public class MfaController {

    private final MfaService mfaService;
    private final UserRepository userRepository;

    public MfaController(MfaService mfaService, UserRepository userRepository) {
        this.mfaService = mfaService;
        this.userRepository = userRepository;
    }

    @PostMapping("/setup")
    public ResponseEntity<ApiResponse<MfaSetupResponse>> setupMfa(
            Authentication authentication,
            HttpServletRequest httpRequest) {

        User user = getCurrentUser(authentication);
        String ipAddress = getClientIpAddress(httpRequest);
        String userAgent = httpRequest.getHeader("User-Agent");

        MfaSetupResponse response = mfaService.setupMfa(user, ipAddress, userAgent);

        return ResponseEntity.ok(ApiResponse.success("MFA setup initiated", response));
    }

    @PostMapping("/confirm")
    public ResponseEntity<ApiResponse<MfaSetupResponse>> confirmMfaSetup(
            @Valid @RequestBody EnableMfaRequest request,
            Authentication authentication,
            HttpServletRequest httpRequest) {

        User user = getCurrentUser(authentication);
        String ipAddress = getClientIpAddress(httpRequest);
        String userAgent = httpRequest.getHeader("User-Agent");

        MfaSetupResponse response = mfaService.confirmMfaSetup(
                user, request.getTotpCode(), ipAddress, userAgent);

        return ResponseEntity.ok(ApiResponse.success(
                "MFA enabled successfully. Save your backup codes securely.", response));
    }

    @PostMapping("/disable")
    public ResponseEntity<ApiResponse<Void>> disableMfa(
            @Valid @RequestBody EnableMfaRequest request,
            Authentication authentication,
            HttpServletRequest httpRequest) {

        User user = getCurrentUser(authentication);
        String ipAddress = getClientIpAddress(httpRequest);
        String userAgent = httpRequest.getHeader("User-Agent");

        mfaService.disableMfa(user, request.getTotpCode(), ipAddress, userAgent);

        return ResponseEntity.ok(ApiResponse.success("MFA has been disabled"));
    }

    private User getCurrentUser(Authentication authentication) {
        String username = authentication.getName();
        return userRepository.findByUsername(username)
                .orElseThrow(() -> new RuntimeException("User not found"));
    }

    private String getClientIpAddress(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }
}

// src/main/java/com/enterprise/auth/controller/BackupCodeController.java
package com.enterprise.auth.controller;

import com.enterprise.auth.dto.ApiResponse;
import com.enterprise.auth.dto.BackupCodeStatusResponse;
import com.enterprise.auth.dto.MfaSetupResponse;
import com.enterprise.auth.entity.User;
import com.enterprise.auth.exception.MfaException;
import com.enterprise.auth.repository.UserRepository;
import com.enterprise.auth.service.BackupCodeService;
import jakarta.servlet.http.HttpServletRequest;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.Authentication;
import org.springframework.web.bind.annotation.*;

import java.util.List;

@RestController
@RequestMapping("/api/backup-codes")
public class BackupCodeController {

    private final BackupCodeService backupCodeService;
    private final UserRepository userRepository;

    public BackupCodeController(BackupCodeService backupCodeService, UserRepository userRepository) {
        this.backupCodeService = backupCodeService;
        this.userRepository = userRepository;
    }

    @GetMapping("/status")
    public ResponseEntity<ApiResponse<BackupCodeStatusResponse>> getBackupCodeStatus(
            Authentication authentication) {

        User user = getCurrentUser(authentication);

        if (!user.isMfaEnabled()) {
            throw new MfaException("MFA is not enabled");
        }

        long remaining = backupCodeService.getRemainingBackupCodeCount(user);
        boolean regenerationRecommended = remaining <= 3;

        String message;
        if (remaining == 0) {
            message = "No backup codes remaining. Please regenerate immediately.";
        } else if (regenerationRecommended) {
            message = "Low backup codes remaining. Consider regenerating.";
        } else {
            message = "Backup codes available.";
        }

        BackupCodeStatusResponse status = new BackupCodeStatusResponse(
                remaining, message, regenerationRecommended);

        return ResponseEntity.ok(ApiResponse.success("Backup code status retrieved", status));
    }

    @PostMapping("/regenerate")
    public ResponseEntity<ApiResponse<MfaSetupResponse>> regenerateBackupCodes(
            Authentication authentication,
            HttpServletRequest httpRequest) {

        User user = getCurrentUser(authentication);
        String ipAddress = getClientIpAddress(httpRequest);
        String userAgent = httpRequest.getHeader("User-Agent");

        List<String> newCodes = backupCodeService.regenerateBackupCodes(user, ipAddress, userAgent);

        MfaSetupResponse response = new MfaSetupResponse(null, null, newCodes,
                "New backup codes generated. All previous codes have been invalidated. " +
                "Save these codes in a secure location.");

        return ResponseEntity.ok(ApiResponse.success("Backup codes regenerated", response));
    }

    private User getCurrentUser(Authentication authentication) {
        String username = authentication.getName();
        return userRepository.findByUsername(username)
                .orElseThrow(() -> new RuntimeException("User not found"));
    }

    private String getClientIpAddress(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }
}

